// proxyHandler fetches content from a user-provided URL and returns it.
func proxyHandler(w http.ResponseWriter, r *http.Request) {
	// Extract the target URL from the query parameter "url"
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter is missing", http.StatusBadRequest)
		return
	}

	// Basic URL validation to ensure it's a valid and supported scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		http.Error(w, fmt.Sprintf("Invalid URL parameter: %v", err), http.StatusBadRequest)
		return
	}
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		http.Error(w, "Only http and https schemes are supported", http.StatusBadRequest)
		return
	}

	log.Printf("Proxying GET request to: %s", targetURL)

	// Perform the GET request to the target URL
	resp, err := http.Get(targetURL)
	if err != nil {
		log.Printf("Error fetching content from %s: %v", targetURL, err)
		http.Error(w, fmt.Sprintf("Failed to fetch content: %v", err), http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close() // Ensure the response body is closed

	// Copy all headers from the upstream response to our response
	for name, values := range resp.Header {
		for _, value := range values {
			w.Header().Add(name, value)
		}
	}

	// Set the status code from the upstream response
	w.WriteHeader(resp.StatusCode)

	// Copy the response body from the upstream server to our client
	_, err = io.Copy(w, resp.Body)
	if err != nil {
		// Log error but cannot send HTTP error as headers might have been sent
		log.Printf("Error copying response body for %s: %v", targetURL, err)
	}
}

